mapper.select:
select c.*, cl.room_number as classroomName from course c left join classroom cl on c.classroom_id = cl.classroom_id
and (c.course_name like concat('%',#{keyword},'%') or c.teacher like concat('%',#{keyword},'%'))
and c.type = #{type}
and c.weekday = #{weekday}
order by c.weekday, c.start_time

mapper.update:
update course
course_name = #{courseName}, teacher = #{teacher}, weekday = #{weekday}, start_time = #{startTime}, end_time = #{endTime}, classroom_id = #{classroomId}, type = #{type},
where course_id = #{courseId}
